code_changes.content:
[
  {
    "file": "lib/base64.c",
    "line": 202,
    "severity": "critical",
    "description": "Integer overflow check removed. The removed overflow validation allowed insize values that could overflow the calculation (insize + 2) / 3 * 4 + 1, leading to undersized buffer allocation and subsequent heap buffer overflow when encoding large inputs.",
    "fix_patch": "--- a/lib/base64.c
+++ b/lib/base64.c
@@ -199,6 +199,11 @@ static CURLcode base64_encode(const char *table64,
   if(!insize)
     insize = strlen(inputbuff);

+#if SIZEOF_SIZE_T == 4
+  if(insize > UINT_MAX/4)
+    return CURLE_OUT_OF_MEMORY;
+#endif
+
   base64data = output = malloc((insize + 2) / 3 * 4 + 1);
   if(!output)
     return CURLE_OUT_OF_MEMORY;
"
  },
  {
    "file": "lib/cookie.c",
    "line": 147,
    "severity": "critical",
    "description": "Off-by-one error in cookie domain matching. The check for the dot separator before the domain part uses incorrect array indexing, testing the wrong character position (first character of domain instead of character before domain). This allows cookies with invalid domain scope to be accepted, bypassing RFC 6265 domain matching rules.",
    "fix_patch": "--- a/lib/cookie.c
+++ b/lib/cookie.c
@@ -144,7 +144,7 @@ static bool cookie_tailmatch(const char *cookie_domain,
    */
   if(hostname_len == cookie_domain_len)
     return TRUE;
-  if('.' == *(hostname + hostname_len - cookie_domain_len))
+  if('.' == *(hostname + hostname_len - cookie_domain_len - 1))
     return TRUE;
   return FALSE;
 }
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 2200,
    "severity": "critical",
    "description": "Missing NULL check after sk_GENERAL_NAME_value. The function sk_GENERAL_NAME_value can return NULL, but the code immediately dereferences the pointer at line 2202 without validation. This causes a NULL pointer dereference when processing a subject alternative name entry that cannot be retrieved.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -2198,6 +2198,8 @@ ossl_verifyhost(struct Curl_easy *data, struct connectdata *conn,
     for(i = 0; (i < numalts) && !dnsmatched; i++) {
       /* get a handle to alternative name number i */
       const GENERAL_NAME *check = sk_GENERAL_NAME_value(altnames, i);
+      if(!check)
+        continue;

       if(check->type == GEN_DNS)
         dNSName = TRUE;
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 2210,
    "severity": "critical",
    "description": "Missing NULL check for ASN1_STRING_get0_data before strlen call. The function ASN1_STRING_get0_data can return NULL, but at line 2224 strlen is called on the result without validation. According to OpenSSL documentation, data returned by ASN1_STRING_get0_data may not be null-terminated. This causes undefined behavior when calling strlen on a NULL pointer.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -2208,6 +2208,8 @@ ossl_verifyhost(struct Curl_easy *data, struct connectdata *conn,
       /* only check alternatives of the same type the target is */
       if(check->type == target) {
         /* get data and length */
         const char *altptr = (char *)ASN1_STRING_get0_data(check->d.ia5);
         size_t altlen = (size_t) ASN1_STRING_length(check->d.ia5);
+        if(!altptr)
+          continue;

         switch(target) {
         case GEN_DNS: /* name/pattern comparison */
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 963,
    "severity": "critical",
    "description": "Missing NULL check for global_passwd parameter before strlen call. The passwd_callback function receives global_passwd as a void pointer parameter which can be NULL. At line 963, strlen is called on the casted parameter without validation, causing undefined behavior if NULL is passed.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -959,6 +959,8 @@ static int passwd_callback(char *buf, int num, int encrypting,
{
   DEBUGASSERT(0 == encrypting);

+  if(!global_passwd)
+    return 0;
   if(!encrypting) {
     int klen = curlx_uztosi(strlen((char *)global_passwd));
     if(num > klen) {
"
  }
]

